    class DSU(val size: Int) {
        val parent = LongArray(size)
        val rank = LongArray(size)
        init {
            for (i in 0 until size) {
                parent[i] = i.toLong()
                rank[i] = 1L
            }
        }
        fun find(x: Long): Long {
            if (parent[x.toInt()] != x) {
                parent[x.toInt()] = find(parent[x.toInt()])
            }
            return parent[x.toInt()]
        }
        fun union(x: Long, y: Long) {
            val xRoot = find(x)
            val yRoot = find(y)
            if (xRoot == yRoot) return
            if (rank[xRoot] < rank[yRoot]) {
                parent[xRoot.toInt()] = yRoot
            } else {
                parent[yRoot.toInt()] = xRoot
                if (rank[xRoot] == rank[yRoot]) {
                    rank[xRoot]++
                }
            }
        }
    }

    val dsu = DSU(c.toInt() + 1)
    for (connection in connections) {
        val u = connection[0]
        val v = connection[1]
        dsu.union(u, v)
    }

    val componentHeaps = mutableMapOf<Long, PriorityQueue<Long>>()
    for (station in 1..c.toInt()) {
        val root = dsu.find(station)
        componentHeaps.getOrPut(root) { PriorityQueue<Long>() }.add(station)
    }

    val online = BooleanArray(c.toInt() + 1) { true }
    val result = mutableListOf<Long>()

    for (query in queries) {
        val type = query[0]
        val x = query[1]
        if (type == 1L) {
            if (online[x.toInt()]) {
                result.add(x)
            } else {
                val root = dsu.find(x)
                val heap = componentHeaps[root] ?: continue
                while (heap.isNotEmpty()) {
                    val top = heap.peek()
                    if (online[top.toInt()]) {
                        break
                    } else {
                        heap.poll()
                    }
